INSERT INTO `scripts` VALUES (2, 'AI发布助手', '', 6, '1.0.0', 1, 'uploads/1782608405513-152677865-00-config.js', 765, 'code', '*', NULL, NULL, NULL, 'published', 106, '2026-06-28 09:00:05', '2026-06-29 07:38:31', 'js', NULL);
